  ('public-health-specialist-moex-00007', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列關於計畫評價的敘述，何者正確？', '["過程評價是找出計畫執行過程中的優點和缺點", "總結性評價是為了瞭解計畫是否按照預計過程執行", "衝擊評價是觀察計畫結束一段時間之後所帶來的效果", "結果評價是計畫立即可觀察的效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00008', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某人生病後，同步接受了西醫和中醫的藥物和治療，又到廟裡找乩童收驚。根據凱博文（Arthur Kleinman）將納入文化考量的醫療體系（culturalmedicinesystem）的定義，此人使用了那些醫療 體系？', '["常民文化加上專業醫療", "專業醫療加上民俗醫療", "常民文化加上民俗醫療", "專業醫療加上民俗醫療加上常民文化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00009', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某社區發展協會理事長發現該社區有水污染的問題，因此籌組工作小組，開始進行社區水污染來 源的調查，雖尚未了解未來應如何預防水污染，但此調查計畫已經獲得很多社區居民的支持。這 個社區計畫可能處於那個「整備程度」階段？', '["模糊覺察期", "計畫前期", "準備期", "穩定期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00010', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關工作負荷控制模式（JobDemand-Controlmodel，簡稱DC）與付出報酬失衡模式（Effort-Reward Imbalance，簡稱ERI），此二模式的描述何者錯誤？', '["DC強調高度工作需求和高度工作控制會引發高度壓力反應帶來健康危害", "ERI認為個人與組織間交換若失衡會引起生理壓力造成健康危害", "ERI認為個人過度控制需求會形成A型人格的壓力因應模式，因而產生健康危害", "DC強調對工作的控制感，而ERI強調人與組織的社會交換"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00011', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某員工某日因為延遲完成主管交辦的有期限之特定任務，因而被主管斥責，造成該員工心裡強烈 不滿，因此認為主管對他有工作欺凌行為。請問這個事件，僅符合工作欺凌的那項條件？', '["長時間持續的條件", "權力不對等", "重複發生", "意圖傷害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
