  ('public-health-specialist-moex-00014', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某學校為提升學生的運動行為，請同學票選運動大使，並培訓這些運動大使成為同學的運動小教 練。此後各個運動小教練自行組隊參加校內競賽，優勝隊伍給予獎勵，此過程顯著增加了全校學 生運動行為。這樣的介入方案採用了何種以社會網絡為基礎的行為改變介入策略？', '["「分割」介入策略", "「改變」介入策略", "「誘導」介入策略", "「意見領袖」介入策略"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
